PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE analysis (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        timestamp INTEGER NOT NULL,
        content TEXT NOT NULL,
        type TEXT DEFAULT 'full'
      );
CREATE TABLE infosec_processed (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title TEXT NOT NULL,
  raw_content TEXT,
  summary TEXT,
  category TEXT,
  risk_score INTEGER,
  entities TEXT,
  source TEXT,
  published TEXT,
  lat REAL,
  lng REAL,
  created_at INTEGER DEFAULT (strftime('%s','now'))
, link TEXT);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_timestamp ON analysis(timestamp);
CREATE INDEX idx_infosec_created ON infosec_processed(created_at);
CREATE INDEX idx_unique_source_title ON infosec_processed(source, title);
COMMIT;
