INSERT INTO infosec_processed VALUES(424,'Targeted espionage against Cambodian government entities','Khmer Shadow组织利用NIGHTFORGE加载器攻击柬埔寨政府部门，采用高级规避技术和COM持久化机制。','柬埔寨政府遭网络间谍攻击','黑客组织',70,'Khmer Shadow, NIGHTFORGE, 柬埔寨政府, 信息收集局, 公共工程与运输部, VMwareNamespaceCmd.exe, Havoc Demon','AlienVault OTX','2026-06-11T14:41:08.187000',NULL,NULL,1781417982,'https://otx.alienvault.com/pulse/6a2aa0fe417d1a6f2b89eec1');
INSERT INTO infosec_processed VALUES(425,'From external espionage to domestic targeting','OceanLotus组织利用SPECTRALVIPER后门攻击越南金融和基建机构，可能与反腐行动相关。','越南APT转向国内间谍','黑客组织',70,'OceanLotus, SPECTRALVIPER, FireAnt Metakit, 越南, Blazing Furnace','AlienVault OTX','2026-06-11T14:30:15.457000',NULL,NULL,1781417991,'https://otx.alienvault.com/pulse/6a2ac312c98386d398eab284');
INSERT INTO infosec_processed VALUES(426,'Sniper''s Nest: From Brand Impersonation to Browser Hijacking and CPA Fraud','假冒政治人物和品牌，通过虚假优惠诱导用户，滥用浏览器通知和重定向进行网络钓鱼和欺诈。','SniperDz钓鱼平台','攻击事件',75,'SniperDz, Facebook, Linktree, Linkbio, 中东, 北非, 网络钓鱼, 品牌假冒','AlienVault OTX','2026-06-11T14:27:52.839000',NULL,NULL,1781418002,'https://otx.alienvault.com/pulse/6a2aa0d6db4e2c52648e2ed7');
INSERT INTO infosec_processed VALUES(427,'Vibe Hacking: Two AI-Augmented Campaigns Target Government and Financial Sectors in Latin America','两种AI增强黑客活动分别用西语和葡语攻击拉美政府与金融机构，利用AI动态生成工具规避检测。','拉美AI黑客攻击政府金融','攻击事件',75,'SHADOW-AETHER-040, SHADOW-AETHER-064, 拉丁美洲, 政府, 金融机构, AI代理, ProxyChains, SSH, Chisel, Neo-reGeorg, CrackMapExec, Impacket','AlienVault OTX','2026-06-11T08:16:08.337000',NULL,NULL,1781418010,'https://otx.alienvault.com/pulse/6a02ea171e7005022d5c8a6f');
INSERT INTO infosec_processed VALUES(428,'China-Linked Fake Consulting Sites Targeting US Clearance Holders Seized','美当局查封13个与中国情报相关的虚假咨询网站，这些网站伪装成合法公司招募美国安全许可持有者窃取机密信息。','中国虚假咨询网站招募美情报人员','攻击事件',75,'中国、美国、虚假咨询网站、安全许可持有者、13个域名、Upwork、Expertia AI、Hubstaff Talent、加密货币、AI生成的头像','AlienVault OTX','2026-06-11T07:38:33.382000',NULL,NULL,1781418033,'https://otx.alienvault.com/pulse/6a2a625931731a23250efb39');
INSERT INTO infosec_processed VALUES(429,'Fake Software Tutorials on TikTok Spread Vidar Stealer','黑客利用TikTok和Instagram虚假软件教程传播Vidar信息窃取程序，通过AI语音和私信链接诱导用户下载。','TikTok虚假教程传播Vidar窃密器','恶意软件',70,'TikTok, Instagram Reels, Vidar, PowerShell, 恶意链接, 假冒Windows账户','AlienVault OTX','2026-06-11T07:37:24.272000',NULL,NULL,1781418039,'https://otx.alienvault.com/pulse/6a298f548047c70cc9e2f4ee');
INSERT INTO infosec_processed VALUES(430,'SilabRAT, What''s Your Power?','SilabRAT is an advanced Remote Access Trojan offered as Malware-as-a-Service on Darkweb forums since late 2025, developed by threat actor o1oo1 and sold for $5,000 monthly. This financially-motivated tool focuses on credential theft and cryptocurrency operations, featuring Hidden Virtual Network Computing for invisible remote control, browser profile cloning to bypass session protections, and automated cryptocurrency wallet password cracking. The RAT bypasses Chrome App-Bound Encryption, performs session hijacking, and includes keylogging, clipboard monitoring, and remote desktop capabilities. Distributed through phishing and ClickFix campaigns with operator-hosted infrastructure, SilabRAT uses ChaCha20-Poly1305 encryption for command-and-control communications. The developer also offers AsmCrypt, a companion crypter service, creating a complete malware bundle from evasion to execution and remote control.','SilabRAT, What''s Your Power?','威胁情报',50,'','AlienVault OTX','2026-06-10T13:45:08.713000',NULL,NULL,1781418055,'https://otx.alienvault.com/pulse/6a2951665d658e753b489765');
